import React, { useState } from 'react';
import { 
  LogIn, 
  User, 
  Layout, 
  Activity, 
  ChevronRight, 
  Edit3, 
  Award, 
  Info,
  Clock,
  CheckCircle,
  TrendingUp,
  Save,
  X
} from 'lucide-react';

/**
 * FITSTACK - HÜSEYİN'İN GEREKSİNİM PANELİ (Aşama 4)
 * Tasarım: Midnight Navy & Neon Lime (Sema'nın efsane stili korunmuştur)
 * Hüseyin'in Gereksinimleri: 2, 4, 6, 8, 10, 12, 14, 16
 */

const App = () => {
  // --- HÜSEYİN'İN STATE YÖNETİMİ ---
  const [isLoggedIn, setIsLoggedIn] = useState(false); // Reg 2
  const [activeTab, setActiveTab] = useState('programs'); // Reg 6 & 10
  const [isEditing, setIsEditing] = useState(false); // Reg 4
  const [selectedProgram, setSelectedProgram] = useState(null); // Reg 8
  const [user, setUser] = useState({ name: 'Hüseyin Ak', email: 'huseyin@fitstack.ai' });
  const [points] = useState(3840); // Reg 12
  const [streak] = useState(21); // Reg 14

  // Reg 6 & 8: Program Listesi
  const [programs] = useState([
    { id: 1, title: 'Iron Strength', level: 'İleri', duration: '12 Hafta', desc: 'Maksimum güç artışı için tasarlanmış ağır direnç programı.' },
    { id: 2, title: 'Yoga Flow', level: 'Başlangıç', duration: '4 Hafta', desc: 'Esneklik ve zihinsel rahatlama sağlayan başlangıç seviye program.' },
    { id: 3, title: 'HIIT Cardio', level: 'Orta', duration: '6 Hafta', desc: 'Yüksek yoğunluklu antrenmanlar ile hızlı yağ yakımı sağlar.' }
  ]);

  // Reg 10 & 12: Geçmiş Antrenmanlar
  const workoutHistory = [
    { id: 201, name: 'Hüseyin - Bench Press Günü', points: 150, date: '24.03' },
    { id: 202, name: 'Hüseyin - Interval Koşu', points: 220, date: '25.03' }
  ];

  // Reg 16: Rozetler
  const badges = [
    { id: 1, name: 'Güç Sembolü', icon: '🔱' },
    { id: 2, name: 'Hız Canavarı', icon: '⚡' }
  ];

  // --- HÜSEYİN'İN FONKSİYONLARI ---

  const handleLogin = (e) => {
    e.preventDefault();
    setIsLoggedIn(true);
  };

  const handleUpdate = (e) => {
    e.preventDefault();
    setIsEditing(false);
    alert("Profil Hüseyin adına güncellendi! (Reg 4)");
  };

  // --- GİRİŞ EKRANI (Reg 2) ---
  if (!isLoggedIn) {
    return (
      <div className="min-h-screen bg-[#020617] flex items-center justify-center p-6 text-slate-100 font-sans">
        <div className="bg-[#0f172a] border border-[#1e293b] p-10 rounded-[3rem] w-full max-w-md shadow-2xl">
          <div className="flex justify-center mb-6">
            <div className="bg-[#d9f99d] p-4 rounded-2xl">
              <LogIn className="text-[#020617] w-8 h-8" />
            </div>
          </div>
          <h2 className="text-3xl font-black text-[#d9f99d] italic mb-2 text-center tracking-tighter uppercase leading-none">FITSTACK LOGIN.</h2>
          <p className="text-slate-500 text-center mb-8 text-[10px] font-bold uppercase tracking-[0.2em]">Hüseyin Giriş Modülü</p>
          <form onSubmit={handleLogin} className="space-y-4">
            <input type="email" placeholder="huseyin@fitstack.ai" className="w-full bg-[#1e293b] border-none p-4 rounded-2xl text-white outline-none focus:ring-2 focus:ring-[#d9f99d]" required />
            <input type="password" placeholder="Şifre" className="w-full bg-[#1e293b] border-none p-4 rounded-2xl text-white outline-none focus:ring-2 focus:ring-[#d9f99d]" required />
            <button type="submit" className="w-full bg-[#d9f99d] text-[#020617] font-black py-4 rounded-2xl hover:bg-[#c4e68c] uppercase tracking-widest shadow-xl">
              Giriş Yap (Reg 2)
            </button>
          </form>
        </div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#020617] text-slate-100 p-6 lg:p-12 font-sans selection:bg-[#d9f99d] selection:text-[#020617]">
      <div className="max-w-7xl mx-auto">

        {/* HEADER: Reg 12 & 14 */}
        <header className="flex flex-col md:flex-row justify-between items-center mb-16 border-b border-[#1e293b] pb-10">
          <div>
            <h1 className="text-5xl font-black text-white italic tracking-tighter uppercase italic">FITSTACK<span className="text-[#d9f99d]">.</span></h1>
            <p className="text-slate-500 uppercase tracking-widest text-[10px] mt-2 font-bold italic underline decoration-[#d9f99d] decoration-2 underline-offset-8">Hüseyin Engineering Panel</p>
          </div>
          <div className="flex gap-4">
             <div className="bg-[#0f172a] border border-[#1e293b] p-5 rounded-3xl flex items-center gap-4">
               <TrendingUp size={28} className="text-[#d9f99d]" />
               <div>
                 <p className="text-[10px] text-slate-500 font-bold uppercase">Tecrübe (Reg 12)</p>
                 <p className="font-black text-2xl text-white">{points} XP</p>
               </div>
             </div>
             <div className="bg-[#0f172a] border border-[#1e293b] p-5 rounded-3xl flex items-center gap-4">
               <Award size={28} className="text-orange-500" />
               <div>
                 <p className="text-[10px] text-slate-500 font-bold uppercase">Seri (Reg 14)</p>
                 <p className="font-black text-2xl text-white">{streak} GÜN</p>
               </div>
             </div>
          </div>
        </header>

        <div className="grid grid-cols-1 lg:grid-cols-12 gap-10">

          {/* SOL PANEL: Reg 4 & 16 */}
          <div className="lg:col-span-4 space-y-8">
            <section className="bg-[#0f172a] border border-[#1e293b] p-8 rounded-[2.5rem]">
              <div className="flex justify-between items-center mb-8">
                <h2 className="text-lg font-bold flex items-center gap-3 text-white"><User className="text-[#d9f99d]" /> Profil (Reg 4)</h2>
                <button onClick={() => setIsEditing(!isEditing)} className="text-slate-500 hover:text-[#d9f99d]"><Edit3 size={18}/></button>
              </div>

              {isEditing ? (
                <form onSubmit={handleUpdate} className="space-y-4">
                  <input type="text" value={user.name} onChange={(e) => setUser({...user, name: e.target.value})} className="w-full bg-[#1e293b] p-4 rounded-xl text-white border border-[#1e293b] outline-none" />
                  <input type="email" value={user.email} onChange={(e) => setUser({...user, email: e.target.value})} className="w-full bg-[#1e293b] p-4 rounded-xl text-white border border-[#1e293b] outline-none" />
                  <button type="submit" className="w-full bg-[#d9f99d] text-slate-950 font-black py-4 rounded-xl uppercase text-[10px] tracking-widest">
                    <Save size={14} className="inline mr-2"/> Profili Kaydet
                  </button>
                </form>
              ) : (
                <div className="bg-[#1e293b]/50 p-6 rounded-3xl border border-[#1e293b]">
                  <p className="text-[10px] text-slate-500 font-bold uppercase mb-1 italic">Hüseyin'in Profili</p>
                  <p className="text-xl font-black text-white uppercase mb-6">{user.name}</p>
                  <p className="text-sm text-slate-400 italic">{user.email}</p>
                </div>
              )}
            </section>

            <section className="bg-[#0f172a] border border-[#1e293b] p-8 rounded-[2.5rem]">
              <h2 className="text-lg font-bold mb-6 text-white flex items-center gap-3"><Award className="text-[#d9f99d]" size={20}/> Rozetler (Reg 16)</h2>
              <div className="flex gap-4">
                {badges.map(b => (
                  <div key={b.id} className="bg-[#1e293b]/50 p-4 rounded-2xl border border-transparent hover:border-[#d9f99d]/20 transition-all">
                    <span className="text-2xl block mb-2">{b.icon}</span>
                    <span className="text-[8px] font-black text-slate-500 uppercase">{b.name}</span>
                  </div>
                ))}
              </div>
            </section>
          </div>

          {/* SAĞ PANEL: Reg 6, 8, 10 */}
          <div className="lg:col-span-8 space-y-8">
            <section className="bg-[#0f172a] border border-[#1e293b] p-10 rounded-[3rem]">
              <div className="flex bg-[#1e293b] p-1.5 rounded-2xl mb-10 inline-flex border border-white/5">
                <button onClick={() => setActiveTab('programs')} className={`px-8 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'programs' ? 'bg-[#d9f99d] text-[#020617]' : 'text-slate-500 hover:text-white'}`}>Programlar (Reg 6)</button>
                <button onClick={() => setActiveTab('history')} className={`px-8 py-3 rounded-xl text-[10px] font-black uppercase tracking-widest transition-all ${activeTab === 'history' ? 'bg-[#d9f99d] text-[#020617]' : 'text-slate-500 hover:text-white'}`}>Geçmiş (Reg 10)</button>
              </div>

              {activeTab === 'programs' ? (
                <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                  {programs.map(p => (
                    <div key={p.id} className="group bg-[#020617]/50 border border-[#1e293b] p-8 rounded-[2.5rem] hover:border-[#d9f99d]/40 transition-all cursor-pointer" onClick={() => setSelectedProgram(p)}>
                      <div className="flex justify-between items-start mb-8">
                        <Layout className="text-slate-500 group-hover:text-[#d9f99d]" size={28} />
                        <ChevronRight className="text-slate-700 group-hover:text-[#d9f99d]" />
                      </div>
                      <h3 className="text-2xl font-black text-white mb-2 uppercase italic">{p.title}</h3>
                      <p className="text-[10px] font-black uppercase text-[#d9f99d]">{p.level} • {p.duration}</p>
                    </div>
                  ))}
                </div>
              ) : (
                <div className="space-y-4">
                  {workoutHistory.map(h => (
                    <div key={h.id} className="flex justify-between items-center p-6 bg-[#020617]/40 border border-[#1e293b] rounded-[2rem] hover:border-white/5 transition-all">
                      <div className="flex items-center gap-6">
                        <Activity className="text-slate-500" size={28} />
                        <div>
                          <h4 className="font-bold text-white text-xl uppercase leading-none mb-2">{h.name}</h4>
                          <span className="text-[10px] text-[#d9f99d] font-black uppercase tracking-widest">+{h.points} XP (Reg 12)</span>
                        </div>
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </section>
          </div>
        </div>
      </div>

      {/* MODAL: Reg 8 */}
      {selectedProgram && (
        <div className="fixed inset-0 bg-[#020617]/95 backdrop-blur-xl flex items-center justify-center p-6 z-50">
          <div className="bg-[#0f172a] border border-[#1e293b] p-12 rounded-[4rem] max-w-xl w-full shadow-2xl">
             <div className="flex justify-between items-start mb-10">
               <Info className="text-[#d9f99d]" size={40} />
               <button onClick={() => setSelectedProgram(null)} className="text-slate-500 hover:text-white">✕</button>
             </div>
             <h3 className="text-4xl font-black text-white mb-2 italic uppercase">{selectedProgram.title}</h3>
             <p className="text-[#d9f99d] text-xs font-black uppercase mb-8 border-b border-[#1e293b] pb-4 tracking-widest">Program Detayları (Reg 8)</p>
             <p className="text-slate-400 text-base italic mb-12 border-l-4 border-[#d9f99d]/20 pl-6">"{selectedProgram.desc}"</p>
             <button onClick={() => {alert("Program Hüseyin adına seçildi!"); setSelectedProgram(null);}} className="w-full py-6 bg-[#d9f99d] text-[#020617] font-black rounded-[2rem] uppercase tracking-widest shadow-2xl">
                PROGRAMA BAŞLA
             </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;
